import React, { useState } from "react";

export default function SavingsDepositScreen({ onDepositToGoal }) {
  const [goalName, setGoalName] = useState("");
  const [amount, setAmount] = useState("");

  const handleDeposit = (e) => {
    e.preventDefault();
    onDepositToGoal(goalName, amount);
    setAmount("");
    setGoalName("");
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-6">
      <h1 className="text-2xl font-bold mb-6">Deposit into Savings</h1>
      <form
        onSubmit={handleDeposit}
        className="w-full max-w-sm bg-white p-6 rounded-2xl shadow-md space-y-4"
      >
        <input
          type="text"
          placeholder="Goal name"
          className="w-full p-3 border rounded-lg"
          value={goalName}
          onChange={(e) => setGoalName(e.target.value)}
          required
        />
        <input
          type="number"
          placeholder="Enter amount"
          className="w-full p-3 border rounded-lg"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          required
        />
        <button className="w-full bg-teal-600 text-white p-3 rounded-lg font-medium hover:bg-teal-700 transition">
          Deposit to Goal
        </button>
      </form>
    </div>
  );
}
